  ('pukao-6f0ba476-moex-00160', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '非法人團體，有無民法規定之權利能力？', '["無權利能力", "有權利能力", "設有代表人或管理人者，有權利能力", "具有獨立財產者，有權利能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00161', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '17歲甲就讀某高中，註冊前竟將父母交給他的學費新臺幣（下同）5萬元，擅自拿去向乙購買A貴 重首飾，當日完成交付該首飾及付款。下列敘述，何者錯誤？', '["A首飾之買賣契約，尚未生效", "5萬元價金之移轉契約，尚未生效", "A首飾之所有權移轉契約，不生效力", "A首飾之買賣契約，經法定代理人承認而生效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00162', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於法律行為及其所附條件或期限之敘述，依民法規定，何者錯誤？', '["附始期法律行為，於期限屆至時，發生效力", "附停止條件法律行為，於條件成就時，失其效力", "結婚行為不得附條件", "因條件成就而受不利益之當事人，如以不正當行為阻礙條件之成就，視為條件已成就"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00163', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲失蹤時剛滿60歲，並經A地方法院依法宣告甲於民國111年6月7日下午12時死亡。下列敘述，何 者與民法規定不符合？', '["計算甲之年齡，自其出生日起算", "宣告甲死亡之時，為其失蹤滿7年之時", "甲視為於111年6月7日下午12時死亡", "於111年6月7日下午12時之前，推定甲仍生存"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00164', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲受監護宣告後，以現金新臺幣1萬元向不知情之乙購買A動產，雙方一手交錢一手交物。下列敘 述，何者錯誤？', '["甲、乙間之買賣契約，無效", "甲取得A動產之所有權", "甲之支付價金行為，屬於處分行為", "甲、乙間之法律行為，不因甲之監護人承認而生效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00165', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲擅自在乙之A地上，建B屋，並種蔬果。下列關於所有權之敘述，何者正確？', '["B屋為土地上之定著物，與土地附合，成為土地之重要且不可分離之部分，為土地之重要成分", "由乙原始取得B屋所有權", "A地上之蔬果，由甲與乙共有", "A地上之蔬果，為土地之成分，由乙取得所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00166', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲對乙有新臺幣10萬元之債權，丙是甲之子，具有行為能力，未經甲之授權，擅以丙自己之名義 將該債權讓與於善意之丁。下列敘述，何者正確？', '["丁得善意取得甲對乙之債權", "丙將債權讓與丁之行為有效", "丙債權讓與，係無權處分", "丙債權讓與，係表見代理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00167', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於寄託物返還之敘述，何者錯誤？', '["返還期限雖經約定，寄託人仍得隨時請求返還", "未定返還期限者，受寄人得隨時返還寄託物", "如定有返還期限者，受寄人絕不得於期限屆滿前返還寄託物", "受寄人返還寄託物時，應一併返還該物之孳息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00168', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲與乙訂立承攬契約，委由乙興建小木屋，並以甲所提供之木材為建築材料。交屋時，甲發現房 屋漏水。下列敘述，何者錯誤？', '["小木屋漏水，若係甲所供給木材性質瑕疵所致，甲雖不得請求減價或解除契約，但得請求乙修補", "小木屋漏水，若係乙過失而施工不當所致，甲得請求乙修補", "小木屋漏水，若與甲所供給木材性質瑕疵無關，甲得定相當期限，請求乙修補之", "小木屋漏水，若與甲所供給木材性質瑕疵無關，如修補所需費用過鉅者，乙得拒絕甲之修補請求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
